from facilitation_helpers import extract_section, section_mentions_any


def test_blocker_triage_addresses_each_story(handback):
    section = extract_section(handback, 'Blocker triage')
    for story_id in ('SHIP-1142', 'SHIP-1156', 'SHIP-1170'):
        assert story_id in section, f'Blocker triage must address {story_id} explicitly.'


def test_po_decision_takes_a_stance(handback):
    section = extract_section(handback, 'PO over-commit decision').lower()
    assert any(k in section for k in ('yes', 'no', 'accept', 'decline', 'reject')), (
        'PO over-commit decision must take a clear stance (yes / no / accept / decline / reject).'
    )
    assert any(k in section for k in ('capacity', 'wip', 'work in progress', 'risk', 'scope')), (
        'PO over-commit decision must reference capacity, WIP, or risk.'
    )


def test_standup_plan_uses_facilitation_language(handback):
    section = extract_section(handback, 'Stand-up plan for tomorrow')
    assert section_mentions_any(section, ['facilitation', 'facilitate']), (
        "Stand-up plan must use 'facilitation' or 'facilitate' (the role-specific signal)."
    )


def test_review_move_addresses_pi_commit(handback):
    section = extract_section(handback, 'End-of-sprint review move').lower()
    assert any(k in section for k in ('pi commit', 'pi commitment', 'feature flag', 'redacted_audit_logs', 'rollout')), (
        'End-of-sprint review move must address the PI commit / feature-flag rollout.'
    )


def test_retro_action_list_prunes_or_sharpens(handback):
    section = extract_section(handback, 'Retro action list \u2014 keep / cut / add').lower()
    decisions = sum(k in section for k in ('keep', 'cut', 'drop', 'remove', 'add', 'sharpen', 'replace'))
    assert decisions >= 2, (
        'Retro action list must show at least two decisions across keep / cut / add.'
    )


def test_leadership_message_is_concise(handback):
    section = extract_section(handback, 'What I\u2019m telling leadership')
    bullet_lines = [line for line in section.splitlines() if line.strip().startswith(('-', '*', '\u2022'))]
    assert len(bullet_lines) >= 2, (
        "'What I'm telling leadership' must use a bulleted format (the Director will read this in stand-up)."
    )
